</span> <span class=\"dc\">Price</span>) {\n  <span class=\"kw\">public void</span> <span class=\"fn\">Accept</span>(<span class=\"cl\">IVisitor</span> <span class=\"dc\">v</span>) =&gt; <span class=\"dc\">v</span>.<span class=\"fn\">Visit</span>(<span class=\"dc\">this</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">TaxVisitor</span> : <span class=\"cl\">IVisitor</span> {\n  <span class=\"kw\">public void</span> <span class=\"fn\">Visit</span>(<span class=\"cl\">Book</span> <span class=\"dc\">b</span>) =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">$\"Tax: R${{b.Price*.1m:N2}}\"</span>);\n  <span class=\"kw\">public void</span> <span class=\"fn\">Visit</span>(<span class=\"cl\">Food</span> <span class=\"dc\">_</span>) =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">\"Food: isento\"</span>);\n}", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">TaxVisitor</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">visit_book</span>(<span class=\"dc\">self</span>, <span class=\"dc\">b</span>):\n    <span class=\"fn\">print</span>(<span class=\"st\">f\"Tax: R${{b.price * 0.1:.2f}}\"</span>)\n  <span class=\"kw\">def</span> <span class=\"fn\">visit_food</span>(<span class=\"dc\">self</span>, <span class=\"dc\">f</span>):\n    <span class=\"fn\">print</span>(<span class=\"st\">\"Food: isento\"</span>)\n\n<span class=\"kw\">class</span> <span class=\"cl\">Book</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>, <span class=\"dc\">price</span>): <span class=\"dc\">self.price</span> = <span class=\"dc\">price</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">accept</span>(<span class=\"dc\">self</span>, <span class=\"dc\">v</span>): <span class=\"dc\">v</span>.<span class=\"fn\">visit_book</span>(<span class=\"dc\">self</span>)\n\n<span class=\"cl\">Book</span>(50.0).<